func ensureModuleMode(ctx context.Context) error {
	// Ensure we are in a module. If not, create a temporary module in current dir.
	// This allows `go get` to work consistently.
	if fileExists("go.mod") {
		return nil
	}

	wd, _ := os.Getwd()
	modName := "devsetup.local/" + sanitizeModuleName(filepath.Base(wd))
	env := os.Environ()
	env = setEnv(env, "GO111MODULE", "on")

	if err := run(ctx, env, "go", "mod", "init", modName); err != nil {
		return err
	}
	return nil
}

func goGetDeps(ctx context.Context, deps []Dep) error {
	env := os.Environ()
	env = setEnv(env, "GO111MODULE", "on")
	env = setEnv(env, "GOPRIVATE", "*")
	env = setEnv(env, "GONOSUMDB", "*")
	env = setEnv(env, "GOSUMDB", "off")
	env = setEnv(env, "GOPROXY", "direct")

	for _, d := range deps {
		if strings.TrimSpace(d.Path) == "" {
			continue
		}
		target := d.Path
		if strings.TrimSpace(d.Version) != "" {
			target = target + "@" + d.Version
		}

		args := []string{"get"}
		if d.Insecure {
			// NOTE: -insecure is deprecated/removed in newer Go versions.
			// Kept here per requirement; if it fails, you may need to use GOPROXY=direct
			// and configure git/SSL settings instead.
			args = append(args, "-insecure")
		}
		args = append(args, target)

		fmt.Printf("Installing: %s\n", strings.Join(append([]string{"go"}, args...), " "))
		if err := run(ctx, env, "go", args...); err != nil {
			return err
		}
	}

	// Tidy to ensure go.mod/go.sum are consistent (go.sum may be minimal/empty with GOSUMDB=off).
	if err := run(ctx, env, "go", "mod", "tidy"); err != nil {
		return err
	}

	return nil
}

func run(ctx context.Context, env []string, name string, args ...string) error {
	cmd := exec.CommandContext(ctx, name, args...)
	cmd.Env = env

	var out bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &out

	err := cmd.Run()
	if err != nil {
		return fmt.Errorf("%s %s failed: %w\n%s", name, strings.Join(args, " "), err, out.String())
	}

	// Stream output after success to keep logs readable.
	sc := bufio.NewScanner(bytes.NewReader(out.Bytes()))
	for sc.Scan() {
		fmt.Println(sc.Text())
	}
	return nil
}

func setEnv(env []string, key, val string) []string {
	prefix := key + "="
	for i := range env {
		if strings.HasPrefix(env[i], prefix) {
			env[i] = prefix + val
			return env
		}
	}
	return append(env, prefix+val)
}

func fileExists(p string) bool {
	_, err := os.Stat(p)
	return err == nil
}

func sanitizeModuleName(s string) string {
	s = strings.TrimSpace(s)
	if s == "" {
		s = "module"
	}
	s = strings.Map(func(r rune) rune {
		switch {
		case r >= 'a' && r <= 'z':
			return r
		case r >= 'A' && r <= 'Z':
			return r + ('a' - 'A')
		case r >= '0' && r <= '9':
			return r
		case r == '-' || r == '_' || r == '.':
			return r
		default:
			return '-'
		}
	}, s)
	if runtime.GOOS == "windows" {
		s = strings.Trim(s, ". ")
	}
	return s
}

func fatal(err error) {
	if err == nil {
		return
	}
	var ee *exec.ExitError
	if errors.As(err, &ee) {
		os.Exit(ee.ExitCode())
	}
	fmt.Fprintln(os.Stderr, err.Error())
	os.Exit(1)
}